1	/**
2	 * The Spider — public types.
3	 *
4	 * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5	 * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6	 * packages can import them without depending on the engine implementation files.
7	 */
8	
9	import type { ZodSchema } from 'zod';
10	
11	// ── Engine instance status ────────────────────────────────────────────
12	
13	export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked';
14	
15	// ── Block record ──────────────────────────────────────────────────────
16	
17	/**
18	 * Persisted record of an active engine block.
19	 * Present on an EngineInstance when status === 'blocked'.
20	 * Cleared when the block is resolved.
21	 */
22	export interface BlockRecord {
23	  /** Block type identifier (matches a registered BlockType.id). */
24	  type: string;
25	  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26	  condition: unknown;
27	  /** ISO timestamp when the engine was blocked. */
28	  blockedAt: string;
29	  /** Optional human-readable message from the engine. */
30	  message?: string;
31	  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32	  lastCheckedAt?: string;
33	}
34	
35	// ── Engine instance ───────────────────────────────────────────────────
36	
37	/**
38	 * A single engine slot within a rig.
39	 *
40	 * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41	 * For the static pipeline it matches `designId`.
42	 *
43	 * `givensSpec` holds literal values set at spawn time (writ, role, commands).
44	 * The Spider assembles `givens` from this directly; upstream yields arrive
45	 * via `context.upstream` as the escape hatch.
46	 */
47	export interface EngineInstance {
48	  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49	  id: string;
50	  /** The engine design to look up in the Fabricator. */
51	  designId: string;
52	  /** Current execution status. */
53	  status: EngineStatus;
54	  /** Engine IDs that must be completed before this engine can run. */
55	  upstream: string[];
56	  /** Literal givens values set at rig spawn time. */
57	  givensSpec: Record<string, unknown>;
58	  /** Yields from a completed engine run (JSON-serializable). */
59	  yields?: unknown;
60	  /** Error message if this engine failed. */
61	  error?: string;
62	  /** Session ID from a launched quick engine, used by the collect step. */
63	  sessionId?: string;
64	  /** ISO timestamp when execution started. */
65	  startedAt?: string;
66	  /** ISO timestamp when execution completed (or failed). */
67	  completedAt?: string;
68	  /** Present when status === 'blocked'. Cleared when the block is resolved. */
69	  block?: BlockRecord;
70	}
71	
72	// ── Rig ──────────────────────────────────────────────────────────────
73	
74	export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
75	
76	/**
77	 * A rig — the execution context for a single writ.
78	 *
79	 * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
80	 * ordered pipeline of engine instances. The Spider updates this document
81	 * in-place as engines run and complete.
82	 */
83	export interface RigDoc {
84	  /** Index signature required to satisfy BookEntry constraint. */
85	  [key: string]: unknown;
86	  /** Unique rig id. */
87	  id: string;
88	  /** The writ this rig is executing. */
89	  writId: string;
90	  /** Current rig status. */
91	  status: RigStatus;
92	  /** Ordered engine pipeline. */
93	  engines: EngineInstance[];
94	  /** ISO timestamp when the rig was created. */
95	  createdAt: string;
96	  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
97	  resolutionEngineId?: string;
98	}
99	
100	// ── Rig filters ───────────────────────────────────────────────────────
101	
102	/**
103	 * Filters for listing rigs.
104	 */
105	export interface RigFilters {
106	  /** Filter by rig status. */
107	  status?: RigStatus;
108	  /** Maximum number of results (default: 20). */
109	  limit?: number;
110	  /** Number of results to skip. */
111	  offset?: number;
112	}
113	
114	// ── Rig templates ─────────────────────────────────────────────────────
115	
116	/**
117	 * A single engine slot declared in a rig template.
118	 */
119	export interface RigTemplateEngine {
120	  /** Engine id unique within this template. */
121	  id: string;
122	  /** Engine design id to look up in the Fabricator. */
123	  designId: string;
124	  /** Engine ids within this template whose completion is required first. Defaults to []. */
125	  upstream?: string[];
126	  /**
127	   * Givens to pass at spawn time.
128	   * String values starting with '$' (either $name or ${name}) are variable
129	   * references resolved at spawn time:
130	   *   '$writ' or '${writ}' — the WritDoc for this rig's writ
131	   *   '$vars.<key>' or '${vars.<key>}' — value from spider.variables config
132	   * Non-string values are passed through literally.
133	   * Variables that resolve to undefined cause the key to be omitted.
134	   */
135	  givens?: Record<string, unknown>;
136	}
137	
138	/**
139	 * A complete rig template.
140	 */
141	export interface RigTemplate {
142	  /** Ordered list of engine slot declarations. */
143	  engines: RigTemplateEngine[];
144	  /**
145	   * Engine id whose yields provide the writ resolution summary.
146	   * Falls back to seal engine, then last completed engine in array order.
147	   */
148	  resolutionEngine?: string;
149	}
150	
151	// ── CrawlResult ────────────────────────────────────────────────────────
152	
153	/**
154	 * The result of a single crawl() call.
155	 *
156	 * Variants, ordered by priority:
157	 * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
158	 * - 'engine-started'    — launched a quick engine's session
159	 * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
160	 * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
161	 * - 'rig-spawned'       — created a new rig for a ready writ
162	 * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
163	 * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
164	 *
165	 * null means no work was available.
166	 */
167	export type CrawlResult =
168	  | { action: 'engine-completed'; rigId: string; engineId: string }
169	  | { action: 'engine-started'; rigId: string; engineId: string }
170	  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
171	  | { action: 'engine-unblocked'; rigId: string; engineId: string }
172	  | { action: 'rig-spawned'; rigId: string; writId: string }
173	  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
174	  | { action: 'rig-blocked'; rigId: string; writId: string };
175	
176	// ── Block type ────────────────────────────────────────────────────────
177	
178	/**
179	 * Result of a block type check.
180	 *
181	 * 'cleared' — condition met, unblock the engine.
182	 * 'pending' — condition not yet met, keep polling.
183	 * 'failed'  — condition is permanently unresolvable, fail the engine.
184	 *
185	 * When status is 'failed', an optional reason provides a human-readable
186	 * explanation that the Spider includes in the engine error message.
187	 */
188	export interface CheckResult {
189	  status: 'cleared' | 'pending' | 'failed';
190	  reason?: string;
191	}
192	
193	/**
194	 * A registered block type — defines how to check whether a blocking
195	 * condition has cleared. Contributed via kit/supportKit `blockTypes`.
196	 */
197	export interface BlockType {
198	  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
199	  id: string;
200	  /**
201	   * Check whether the blocking condition has been resolved.
202	   *
203	   * Return { status: 'cleared' } when the condition is met.
204	   * Return { status: 'pending' } when the condition is not yet met.
205	   * Return { status: 'failed' } or { status: 'failed', reason: '...' }
206	   * when the condition is permanently unresolvable.
207	   *
208	   * Throwing is reserved for transient errors (network failures, etc.)
209	   * — the engine stays blocked and the checker is retried next cycle.
210	   */
211	  check: (condition: unknown) => Promise<CheckResult>;
212	  /** Zod schema for validating the condition payload at block time. */
213	  conditionSchema: ZodSchema;
214	  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
215	  pollIntervalMs?: number;
216	}
217	
218	// ── SpiderApi ─────────────────────────────────────────────────────────
219	
220	/**
221	 * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
222	 */
223	export interface SpiderApi {
224	  /**
225	   * Execute one step of the crawl loop.
226	   *
227	   * Priority ordering: collect > checkBlocked > run > spawn.
228	   * Returns null when no work is available.
229	   */
230	  crawl(): Promise<CrawlResult | null>;
231	
232	  /**
233	   * Show a rig by id. Throws if not found.
234	   */
235	  show(id: string): Promise<RigDoc>;
236	
237	  /**
238	   * List rigs with optional filters, ordered by createdAt descending.
239	   */
240	  list(filters?: RigFilters): Promise<RigDoc[]>;
241	
242	  /**
243	   * Find the rig for a given writ. Returns null if no rig exists.
244	   */
245	  forWrit(writId: string): Promise<RigDoc | null>;
246	
247	  /**
248	   * Manually clear a block on a specific engine, regardless of checker result.
249	   * Throws if the engine is not blocked.
250	   */
251	  resume(rigId: string, engineId: string): Promise<void>;
252	
253	  /**
254	   * Look up a registered block type by ID.
255	   */
256	  getBlockType(id: string): BlockType | undefined;
257	}
258	
259	// ── Configuration ─────────────────────────────────────────────────────
260	
261	/**
262	 * Spider apparatus configuration — lives under the `spider` key in guild.json.
263	 */
264	export interface SpiderConfig {
265	  /**
266	   * Polling interval for crawlContinual tool (milliseconds).
267	   * Default: 5000.
268	   */
269	  pollIntervalMs?: number;
270	  /**
271	   * Build command to pass to quick engines.
272	   */
273	  buildCommand?: string;
274	  /**
275	   * Test command to pass to quick engines.
276	   */
277	  testCommand?: string;
278	  /**
279	   * Writ type → rig template mappings.
280	   * 'default' key is the fallback for unmatched writ types.
281	   * Spawning fails if no matching template is found.
282	   */
