1	/**
2	 * The Spider — rig execution engine apparatus.
3	 *
4	 * The Spider drives writ-to-completion by managing rigs: ordered pipelines
5	 * of engine instances. Each crawl() call performs one unit of work:
6	 *
7	 *   collect > checkBlocked > run > spawn   (priority order)
8	 *
9	 * collect      — check running engines for terminal session results
10	 * checkBlocked — poll registered block type checkers; unblock engines when cleared
11	 * run          — execute the next pending engine (clockwork inline, quick → launch)
12	 * spawn        — create a new rig for a ready writ with no existing rig
13	 *
14	 * CDC on the rigs book (Phase 1 cascade) transitions the associated writ
15	 * when a rig reaches a terminal state (completed or failed).
16	 * The blocked status does NOT trigger the CDC handler.
17	 *
18	 * See: docs/architecture/apparatus/spider.md
19	 */
20	
21	import type { Plugin, StartupContext, LoadedPlugin } from '@shardworks/nexus-core';
22	import { guild, generateId, isLoadedKit, isLoadedApparatus } from '@shardworks/nexus-core';
23	import type { StacksApi, Book, ReadOnlyBook, WhereClause } from '@shardworks/stacks-apparatus';
24	import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
25	import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
26	import type { SessionDoc } from '@shardworks/animator-apparatus';
27	
28	import type {
29	  RigDoc,
30	  RigFilters,
31	  EngineInstance,
32	  SpiderApi,
33	  CrawlResult,
34	  SpiderConfig,
35	  BlockRecord,
36	  BlockType,
37	  CheckResult,
38	  RigTemplate,
39	} from './types.ts';
40	
41	import {
42	  draftEngine,
43	  implementEngine,
44	  reviewEngine,
45	  reviseEngine,
46	  sealEngine,
47	} from './engines/index.ts';
48	
49	import {
50	  writStatusBlockType,
51	  scheduledTimeBlockType,
52	  bookUpdatedBlockType,
53	  patronInputBlockType,
54	} from './block-types/index.ts';
55	
56	import {
57	  crawlOneTool,
58	  crawlContinualTool,
59	  rigShowTool,
60	  rigListTool,
61	  rigForWritTool,
62	  rigResumeTool,
63	  inputRequestListTool,
64	  inputRequestShowTool,
65	  inputRequestAnswerTool,
66	  inputRequestCompleteTool,
67	  inputRequestRejectTool,
68	  inputRequestExportTool,
69	  inputRequestImportTool,
70	} from './tools/index.ts';
71	
72	// ── Helpers ────────────────────────────────────────────────────────────
73	
74	/**
75	 * Check whether a value is JSON-serializable.
76	 * Non-serializable yields cause engine failure — the Stacks cannot store them.
77	 */
78	function isJsonSerializable(value: unknown): boolean {
79	  try {
80	    JSON.stringify(value);
81	    return true;
82	  } catch {
83	    return false;
84	  }
85	}
86	
87	/**
88	 * Build the upstream yields map for a rig: all completed engine yields
89	 * keyed by engine id. Passed as context.upstream to the engine's run().
90	 */
91	function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
92	  const upstream: Record<string, unknown> = {};
93	  for (const engine of rig.engines) {
94	    if (engine.status === 'completed' && engine.yields !== undefined) {
95	      upstream[engine.id] = engine.yields;
96	    }
97	  }
98	  return upstream;
99	}
100	
101	/**
102	 * Find the first pending engine whose entire upstream is completed.
103	 * Returns null if no runnable engine exists.
104	 */
105	function findRunnableEngine(rig: RigDoc): EngineInstance | null {
106	  for (const engine of rig.engines) {
107	    if (engine.status !== 'pending') continue;
108	    const allUpstreamDone = engine.upstream.every((upstreamId) => {
109	      const dep = rig.engines.find((e) => e.id === upstreamId);
110	      return dep?.status === 'completed';
111	    });
112	    if (allUpstreamDone) return engine;
113	  }
114	  return null;
115	}
116	
117	/**
118	 * Determine whether a rig should enter the blocked state.
119	 *
120	 * A rig is blocked when:
121	 * - No engine is currently running
122	 * - No engine is runnable (pending with all upstream completed)
123	 * - At least one engine is blocked
124	 */
125	function isRigBlocked(engines: EngineInstance[]): boolean {
126	  const hasRunning = engines.some((e) => e.status === 'running');
127	  if (hasRunning) return false;
128	  const hasBlocked = engines.some((e) => e.status === 'blocked');
129	  if (!hasBlocked) return false;
130	  // Check runnability by constructing a minimal RigDoc-like object
131	  const syntheticRig = { engines } as RigDoc;
132	  return findRunnableEngine(syntheticRig) === null;
133	}
134	
135	// ── Template-based rig building ────────────────────────────────────────
136	
137	/**
138	 * Normalize a variable reference by stripping optional curly braces.
139	 * '${foo}' → '$foo', '$foo' → '$foo' (unchanged).
140	 * Called before matching against known variable patterns.
141	 */
142	function normalizeVarRef(value: string): string {
143	  if (value.startsWith('${') && value.endsWith('}')) {
144	    return '$' + value.slice(2, -1);
145	  }
146	  return value;
147	}
148	
149	/**
